// src/pages/Login.jsx
import React from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Login.css";

export default function Login() {
  const navigate = useNavigate();

  function handleLogin(e) {
    e.preventDefault();
    const rollNo = e.target.rollno.value.trim();
    const password = e.target.password.value;

    const savedRoll = localStorage.getItem("rollNumber");
    const savedPass = localStorage.getItem("password");

    if (rollNo === savedRoll && password === savedPass) {
      alert("Login successful!");
      navigate("/dashboard");
    } else {
      alert("Invalid credentials. Try again.");
    }
  }

  return (
    <div className="split-layout">
      <div className="left-panel">
        <h1>🎓 Campus Connect</h1>
        <div className="tagline-box">
          <h2>Wide College Network</h2>
          <p>Favorite Space To Connect!</p>
        </div>
        <img
          src="https://img.freepik.com/premium-vector/graduation-students_1214-321.jpg"
          alt="Graduates"
          className="illustration"
        />
      </div>

      <div className="right-panel">
        <div className="form-box shadow-card">
          <div className="tabs">
            <Link to="/login" className="tab active">Login</Link>
            <Link to="/register" className="tab">Signup</Link>
          </div>

          <h2>Login</h2>
          <form onSubmit={handleLogin}>
            <label>University Roll Number</label>
            <input name="rollno" type="text" placeholder="Enter your roll number" required />

            <label>Password</label>
            <input name="password" type="password" placeholder="Enter your password" required />

            <button type="submit">Login</button>
          </form>

          <p style={{ textAlign: "right", marginTop: "10px" }}>
            <Link to="/forgot" className="forgot-link">Forgot Password?</Link>
          </p>

          <p className="signup-cta">
            New to Campus Connect? <Link to="/register"><strong>Signup</strong></Link>
          </p>
        </div>
      </div>
    </div>
  );
}
